import Foundation

enum NetworkError: Error {
    case invalidURL
    case requestFailed
}

class HTTPClient {
    
    private let session = URLSession.shared
    
    func request(_ urlString: String, method: String = "GET", completion: @escaping (Result<Data?, NetworkError>) -> Void) {
        guard let url = URL(string: urlString) else {
            completion(.failure(.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = method
        
        // Allow insecure connections for legacy devices
        if urlString.hasPrefix("http://") {
            let semaphore = DispatchSemaphore(value: 0)
            let configuration = URLSessionConfiguration.default
            configuration.httpAdditionalHeaders = ["Content-Type": "application/json"]
            
            let sessionWithCustomDelegate = URLSession(configuration: configuration, delegate: self, delegateQueue: OperationQueue.main)
            
            sessionWithCustomDelegate.dataTask(with: request) { data, response, error in
                if let error = error {
                    print("Error: \(error)")
                    completion(.failure(.requestFailed))
                } else {
                    completion(.success(data))
                }
                semaphore.signal()
            }.resume()
            
            semaphore.wait()
        } else {
            session.dataTask(with: request) { data, response, error in
                if let error = error {
                    print("Error: \(error)")
                    completion(.failure(.requestFailed))
                } else {
                    completion(.success(data))
                }
            }.resume()
        }
    }
}

extension HTTPClient: URLSessionDelegate {
    
    func urlSession(_ session: URLSession, didReceive challenge: URLAuthenticationChallenge, completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void) {
        if challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust,
           let serverTrust = challenge.protectionSpace.serverTrust {
            
